const txt = $input.first().json.text || '';
const pick = (re, d='') => (txt.match(re)?.[1] || d).trim();
const clean = txt.replace(/#\w+(:[^\s]+)?/g,'').trim();
const title = clean || '제목없음';
const owner = pick(/#owner:([^#]+)/i, '미지정');
const dueRaw = pick(/#due:([^#]+)/i, '');
const priority = pick(/#priority:([^#]+)/i, 'medium').toLowerCase();
const topic = pick(/#topic:([^#]+)/i, 'General');
const status = /#done/i.test(txt) ? 'Done' : /#doing/i.test(txt) ? 'Doing' : 'To do';
return [{ json: { raw: txt, title, owner, dueRaw, priority, topic, status } }];
